nt`)),`enabled`=1,`status`='NORMAL',`updated_at`=@mianjing_created_at,`deleted_at`=NULL;INSERT INTO `blog_tag` (`name`,`description`,`use_count`,`enabled`,`status`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES ('Spring Boot','项目总结自动导入标签：Spring Boot',2,1,'NORMAL',@mianjing_created_at,@mianjing_created_at,NULL,0) ON DUPLICATE KEY UPDATE `description`=VALUES(`description`),`use_count`=GREATEST(`use_count`,VALUES(`use_count`)),`enabled`=1,`status`='NORMAL',`updated_at`=@mianjing_created_at,`deleted_at`=NULL;INSERT INTO `blog_tag` (`name`,`description`,`use_count`,`enabled`,`status`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES ('Thrift','项目总结自动导入标签：Thrift',1,1,'NORMAL',@mianjing_created_at,@mianjing_created_at,NULL,0) ON DUPLICATE KEY UPDATE `description`=VALUES(`description`),`use_count`=GREATEST(`use_count`,VALUES(`use_count`)),`enabled`=1,`status`='NORMAL',`updated_at`=@mianjing_created_at,`deleted_at`=NULL;INSERT INTO `blog_tag` (`name`,`description`,`use_count`,`enabled`,`status`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES ('事件驱动','项目总结自动导入标签：事件驱动',1,1,'NORMAL',@mianjing_created_at,@mianjing_created_at,NULL,0) ON DUPLICATE KEY UPDATE `description`=VALUES(`description`),`use_count`=GREATEST(`use_count`,VALUES(`use_count`)),`enabled`=1,`status`='NORMAL',`updated_at`=@mianjing_created_at,`deleted_at`=NULL;INSERT INTO `blog_tag` (`name`,`description`,`use_count`,`enabled`,`status`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES ('加密解密','项目总结自动导入标签：加密解密',1,1,'NORMAL',@mianjing_created_at,@mianjing_created_at,NULL,0) ON DUPLICATE KEY UPDATE `description`=VALUES(`description`),`use_count`=GREATEST(`use_count`,VALUES(`use_count`)),`enabled`=1,`status`='NORMAL',`updated_at`=@mianjing_created_at,`deleted_at`=NULL;INSERT INTO `blog_tag` (`name`,`description`,`use_count`,`enabled`,`status`,`created_at`,`updated_at`,`deleted_at`,`version`) VALUES ('协议适配','项目总结自动导入标签：协议适配',1,1,'NORMAL',@mianjing_created_at,@mianjing_created_at,NUL